class Playground {
    async run(inputs) {
        let grid = [];
        try {
            grid = JSON.parse(inputs[0]);
        } catch (e) {
            this.log("Invalid input. Please provide a valid JSON 2D array.");
            return 0;
        }

        const rows = grid.length;
        if (rows === 0) return 0;
        const cols = grid[0].length;

        // Initialize slots
        this.grid_slot.init(grid);
        const visited = Array.from({ length: rows }, () => Array(cols).fill(0));
        this.visited_slot.init(visited);
        this.stack_slot.init([]);
        this.vars_slot.init([["Islands", 0]]);
        this.recursion_slot.init();
        this.callstack_slot.init();

        let islandCount = 0;

        const dfs = async (r, c, parentId) => {
            const nodeId = `node-${r}-${c}`;

            // Visualization: Recursion and Call Stack entry
            this.callstack_slot.pushFrame("dfs", { row: r, col: c });
            this.recursion_slot.enterNode(nodeId, `(${r},${c})`);
            this.stack_slot.push(`(${r},${c})`);

            // Mark as visited
            visited[r][c] = 1;
            this.visited_slot.setCell(r, c, 1);
            this.visited_slot.highlight(r, c, "#00f5a0");
            this.grid_slot.highlight(r, c, "#00e0ff");

            this.log(`Exploring land at (${r}, ${c})`);
            await this.await();

            const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];
            for (const [dr, dc] of directions) {
                const nr = r + dr;
                const nc = c + dc;

                if (nr >= 0 && nr < rows && nc >= 0 && nc < cols) {
                    this.grid_slot.highlight(nr, nc, "#ffb703");
                    this.log(`Checking neighbor (${nr}, ${nc})`);
                    await this.await();

                    if (grid[nr][nc] === "1" && !visited[nr][nc]) {
                        await dfs(nr, nc, nodeId);
                    }
                    this.grid_slot.highlight(nr, nc, null);
                }
            }

            // Visualization: Clean up after finishing this node
            this.stack_slot.pop();
            this.callstack_slot.popFrame();
            this.recursion_slot.exitNode();
            this.grid_slot.highlight(r, c, "#6c8cff");
        };

        for (let r = 0; r < rows; r++) {
            for (let c = 0; c < cols; c++) {
                this.grid_slot.highlight(r, c, "#ffb703");
                this.log(`Scanning cell (${r}, ${c})`);
                await this.await();

                if (grid[r][c] === "1" && !visited[r][c]) {
                    islandCount++;
                    this.vars_slot.put("Islands", islandCount);
                    this.log(`Found new island! Total: ${islandCount}. Starting DFS.`);
                    await this.await();

                    await dfs(r, c, "root");
                } else {
                    this.grid_slot.highlight(r, c, null);
                }
            }
        }

        this.log(`Final count of islands: ${islandCount}`);
        return islandCount;
    }
}
